def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for a in range(10, 0, -1):
                for b in range(1, a * 2):
                    term = ((ratio - a)**4)/(a + b/2 + 1) * np.tanh(b * ratio / (a + 1))
                    priority += term * np.cos(ratio * b / (a + 0.5))
            priority += np.exp(ratio / 4) * np.sin(ratio * 2.3)**3
        elif 6 < ratio <= 10:
            temp = 0
            for x in range(1, int(np.ceil(ratio)) + 5):
                for y in range(1, x + 5):
                    expr = np.sin(ratio * x / (y + 0.1)) * ((ratio - x)**2) / (y + 1.5)
                    temp += expr
            priority = np.tanh(temp) * 15 - np.log1p(ratio) * 3
        elif 3 < ratio <= 6:
            s = 0
            pow_max = int(np.ceil(ratio*3))
            for p in range(1, pow_max):
                s += ((ratio - 3)**p) / (p*1.2) * np.cos(p * ratio * 1.3)
            priority = s * np.exp(-ratio/8) + np.tanh(ratio - 4) * 2
        elif 1.5 <= ratio <= 3:
            s1 = 0
            s2 = 1
            for n in range(1, 15):
                factor = ((ratio - 1.5) ** n) / (n**2 + 1)
                s1 += factor * np.sin(n * ratio * 0.9)
                if n % 2 == 0:
                    s2 *= np.cos(n * ratio / 2)
            priority = s1 + np.log(ratio + 1) * s2
        elif 0.7 <= ratio < 1.5:
            s = 0
            for m in range(1, 20, 2):
                s += ((1.5 - ratio) ** m) / (m * 2.5) * np.sin(m * ratio * 2.5)
            if bin_cap > item * 0.9:
                adjust = np.cos(15 * ratio) ** 2
            else:
                adjust = np.sqrt(np.abs(ratio - 1)) * 5
            priority = s + adjust + np.exp(-ratio)
        elif 0.4 <= ratio < 0.7:
            val = 0
            for j in range(1, 30):
                val += ((0.7 - ratio) ** j) / (j * 3) * np.cos(j * item * 1.4)
            if (i * int(item * 2)) % 5 == 0:
                val *= np.log1p(bin_cap) * 1.5
            else:
                val /= (np.sqrt(bin_cap + 2) + 1.7)
            priority = val - np.tanh(ratio * 5) * 3
        elif 0.1 <= ratio < 0.4:
            s = 0
            for k in range(1, 25):
                s += ((0.4 - ratio) ** k) / (k + 2) * np.sin(k * ratio * 3)
            if bin_cap < item * 0.3:
                penalty = np.log1p(item * bin_cap) * 7
            else:
                penalty = -np.exp(-ratio * 4) * 5
            priority = s + penalty
            for l in range(1, 10):
                priority += ((0.4 - ratio) ** l) / (l * 4) * np.cos(item * l * 0.7)
        else:
            s = 0
            for w in range(1, 20):
                s += ((0.1 - ratio) ** w) / (w * 5) * np.cos(w * item * 1.2)
            multiplier = 2 if int(item * 0.8) % 3 == 0 else 0.5
            penalty = np.log1p(item * bin_cap) * 6 if bin_cap < item * 0.2 else -np.exp(-ratio * 3) * 6
            priority = s * multiplier + penalty
            for z in range(1, 12):
                priority += ((0.1 - ratio) ** z) / (z * 6) * np.sin(item * z * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 1.5 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for offset in range(1, 6):
            idx_sum = i + offset
            if idx_sum % 4 == 0:
                priority += np.sin(ratio * idx_sum * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * idx_sum * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.7
        if (i * item) % 7 == 0:
            priority += np.sin(ratio * item * i * 0.8) * 1.2
        else:
            priority -= np.cos(ratio * item * i * 0.8) * 1.2
        priorities[i] = priority
    return priorities
